        urgency = urgency_score(arrival_time, time_windows[idx])
        dispersion = calculate_dispersion_score(customer_pos, all_truck_pos)

        score = t_time + 10 * urgency - 0.1 * dispersion
        scores.append(score)

    best_node = np.argmin(scores)

    return best_node

