        return np.linalg.norm(pos2 - pos1)

    def travel_time(from_pos, to_pos):
        distance = euclidean_distance(from_pos, to_pos)
        return distance / truck_speed

    def urgency_score(time, window):
        if time < window[0]:
            return (window[0] - time) ** 2
        elif time > window[1]:
            return (time - window[1]) ** 2
        else:
            return 0

    def calculate_cost(customer_idx, current_temp, urgency_weights):
        customer_pos = unvisited_customers[customer_idx]
        travel_cost = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_cost
        urgency = urgency_score(arrival_time, time_windows[customer_idx])
        return (travel_cost + urgency_weights * urgency) / current_temp

    temperature = 1.0
    cooling_rate = 0.99
    min_temperature = 0.01
    num_iterations = 100

    current_index = 0
    current_cost = calculate_cost(current_index, temperature, 10)

    while temperature > min_temperature:
        for _ in range(num_iterations):
            candidate_index = random.randint(0, len(unvisited_customers) - 1)
            candidate_cost = calculate_cost(candidate_index, temperature, 10)

            if candidate_cost < current_cost or random.random() < np.exp((current_cost - candidate_cost) / temperature):
                current_index = candidate_index
                current_cost = candidate_cost

        temperature *= cooling_rate

    best_node = current_index
    return best_node

